651	
652	    const oldLabel = btn.innerHTML;
653	    btn.disabled   = true;
654	    btn.innerHTML  = "Wird gesendet\u2026";
655	
656	    const payload = {
657	      email:          el.value,
658	      anwendungsfall: state.usecase    || "",
659	      modell:         state.modelType  || "",
660	      nutzer:         state.users      || "",
661	      kontext:        state.context    || "",
662	      latenz:         state.latency    || "",
663	      gpu:            state.gpu        || "",
664	      server:         state.server     || "",
665	      platform:       state.platform   || "",
666	      price:          state.price      || "",
667	      tier:           String(state.tier || 2),
668	      quelle:         "AI Factory Wizard",
669	      timestamp:      new Date().toISOString()
670	    };
671	
672	    fetch(SUBMIT_ENDPOINT, {
673	      method:  "POST",
674	      headers: { "Content-Type": "application/json" },
675	      body:    JSON.stringify(payload)
676	    })
677	    .catch(() => { /* fail-soft */ })
678	    .finally(() => {
679	      btn.disabled  = false;
680	      btn.innerHTML = oldLabel;
681	      goTo(6); // \u2192 Danke-Screen
682	    });
683	  }
684	
685	  function buildReportUrl(email) {
686	    const params = [
687	      ["uc",    state.usecase   || ""],
688	      ["u",     state.users     || ""],
689	      ["ctx",   state.context   || ""],
690	      ["lat",   state.latency   || ""],
691	      ["mt",    state.modelType || ""],
692	      ["plat",  state.platform  || ""],
693	      ["price", state.price     || ""],
694	      ["tier",  String(state.tier || 2)],
695	      ["email", email           || ""]
696	    ].map(([k,v]) => encodeURIComponent(k) + "=" + encodeURIComponent(v)).join("&");
697	    state._reportUrl = "AI Factory Report.html#" + params;
698	  }
699	
700	  function openReport() {
701	    if (state._reportUrl) window.open(state._reportUrl, "_blank");
702	  }
703	
