650	  function submitForm(){
651	    const el  = document.getElementById("emailInput");
652	    const btn = document.querySelector(".btn-submit");
653	    if(!el.value || !el.value.includes("@")){
654	      el.style.borderColor = "rgba(218,0,44,.6)";
655	      el.focus();
656	      return;
657	    }
658	    el.style.borderColor = "";
659	
660	    const oldLabel = btn.innerHTML;
661	    btn.disabled   = true;
662	    btn.innerHTML  = "Wird gesendet\u2026";
663	
664	    const payload = {
665	      email:          el.value,
666	      anwendungsfall: state.usecase    || "",
667	      modell:         state.modelType  || "",
668	      nutzer:         state.users      || "",
669	      kontext:        state.context    || "",
670	      latenz:         state.latency    || "",
671	      gpu:            state.gpu        || "",
672	      server:         state.server     || "",
673	      platform:       state.platform   || "",
674	      preis:          state.price      || "",
675	      tier:           String(state.tier || 2),
676	      quelle:         "AI Factory Wizard",
677	      timestamp:      new Date().toISOString()
678	    };
679	
680	    fetch("https://formspree.io/f/" + FORMSPREE_ID, {
681	      method:  "POST",
682	      headers: { "Content-Type": "application/json", "Accept": "application/json" },
683	      body:    JSON.stringify(payload)
684	    })
685	    .then(res => res.json())
686	    .then(data => {
687	      buildReportUrl(el.value);
688	      goTo(6); // immer weiter, egal ob ok oder nicht — Daten sind in Formspree
689	    })
690	    .catch(() => {
691	      buildReportUrl(el.value);
692	      goTo(6); // Netzwerkfehler: fail-soft
693	    })
694	    .finally(() => {
695	      btn.disabled  = false;
696	      btn.innerHTML = oldLabel;
697	    });
698	  }
699	
700	  function buildReportUrl(email) {
701	    const params = [
702	      ["uc",    state.usecase   || ""],
703	      ["u",     state.users     || ""],
704	      ["ctx",   state.context   || ""],
705	      ["lat",   state.latency   || ""],
706	      ["mt",    state.modelType || ""],
707	      ["plat",  state.platform  || ""],
708	      ["price", state.price     || ""],
709	      ["tier",  String(state.tier || 2)],
710	      ["email", email           || ""]
711	    ].map(([k,v]) => encodeURIComponent(k) + "=" + encodeURIComponent(v)).join("&");
712	    state._reportUrl = "AI Factory Report v2.html#" + params;
713	  }
714	
715	  function openReport() {
716	    if (state._reportUrl) window.open(state._reportUrl, "_blank");
717	  }
718	
719	  function restart(){Object.keys(state).forEach(k=>delete state[k]);goTo(0);}
